/**
 * Generates src/generated/default-endpoint.ts from the SKIP_DEFAULT_BASE_URL
 * environment variable. Runs before every build (see the package build script).
 *
 * The generated file is gitignored: the production Skip endpoint is baked into
 * published npm artifacts by the publish workflow (which sets the env var from a
 * GitHub repo variable) without ever being committed to this public repo. Local
 * builds without the env var bake `undefined`, so from-source developers configure
 * the endpoint via ASK_SKIP_CHAT_URL as before.
 */
import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const outFile = join(dirname(fileURLToPath(import.meta.url)), '..', 'src', 'generated', 'default-endpoint.ts');
const baseURL = process.env.SKIP_DEFAULT_BASE_URL?.trim().replace(/\/+$/, '') || undefined;

mkdirSync(dirname(outFile), { recursive: true });
writeFileSync(
    outFile,
    `// GENERATED by scripts/gen-default-endpoint.mjs — do not edit, not committed.\n` +
    `/** Skip API base URL baked in at build time from SKIP_DEFAULT_BASE_URL; undefined when the env var was unset. */\n` +
    `export const DEFAULT_SKIP_BASE_URL: string | undefined = ${JSON.stringify(baseURL)};\n`,
);
console.log(`[gen-default-endpoint] DEFAULT_SKIP_BASE_URL = ${baseURL ?? '(undefined — SKIP_DEFAULT_BASE_URL not set)'}`);
